using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo checks availability and returns false
//    if the resolver can't provide metadata for the requested type.
//    Here we use an options instance with NO resolver to demonstrate the "not available" path.
var emptyOptions = new JsonSerializerOptions
{
    TypeInfoResolver = null   // no resolver → no metadata available
};

bool available = emptyOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"Metadata available with empty resolver? {available} (info is null: {info is null})");

// Also show the success path with TryGetTypeInfo
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2);
Console.WriteLine($"Metadata available with default resolver? {found} (type: {info2?.Type.Name})");

public record Person(string Name, int Age);
EOF

